export function getHomebuilderBySlug(slug: string): Homebuilder | undefined {
    return homebuilders.find(b => b.slug === slug)
}

export function getAllHomebuilderSlugs(): string[] {
    return homebuilders.map(b => b.slug)
}

export function getAllHomebuildersSortedByRank(): Homebuilder[] {
    return [...homebuilders].sort((a, b) => a.rank - b.rank)
}
